const spec = $('Compute Audiences').first().json;
const url = $env.SLACK_WEBHOOK_URL;
const resume = $execution.resumeUrl;
const lines = ['*Audience Sync needs approval* — portal ' + spec.portalId, 'reasons: ' + (spec.approval.reasons.join('; ') || 'threshold exceeded')];
for (const seg of ['suppression', 'retarget', 'seed']) { const d = spec.segments[seg]; if (d) lines.push(seg + ': +' + d.adds.length + ' / -' + d.removes.length + ' (total ' + d.total + ')'); }
lines.push('Approve: ' + resume + '?approved=true');
lines.push('Reject: ' + resume + '?approved=false');
const text = lines.join('\n');
if (url) { try { await this.helpers.httpRequest({ method: 'POST', url: url, body: { text: text }, json: true }); } catch (e) {} }
else { console.log('[audience-sync] approval needed (no SLACK_WEBHOOK_URL):\n' + text); }
return [{ json: spec }];

const spec = $('Compute Audiences').first().json;
const url = $env.SLACK_WEBHOOK_URL;
const text = '*Audience Sync* — portal ' + spec.portalId + ' :no_entry: rejected by reviewer; no changes applied.';
if (url) { try { await this.helpers.httpRequest({ method: 'POST', url: url, body: { text: text }, json: true }); } catch (e) {} }
else { console.log('[audience-sync] ' + text); }
return [{ json: { rejected: true, portalId: spec.portalId } }];

// Both the auto-approved and human-approved paths converge here; re-load the spec
// (a resumed Wait replaces the item with the approval payload).
return [{ json: $('Compute Audiences').first().json }];

const spec = $('Compute Audiences').first().json;
const dryRun = String($env.PP_DRY_RUN || '').toLowerCase() === 'true';
const RES = { platform: 'meta', dryRun: dryRun, segments: {}, status: 'ok', detail: '' };
const token = $env.META_ACCESS_TOKEN || $env.META_CAPI_TOKEN, act = $env.META_AD_ACCOUNT_ID;
if (!token || !act) { RES.status = 'error'; RES.detail = 'META_ACCESS_TOKEN / META_AD_ACCOUNT_ID unset'; return [{ json: { ...spec, meta: RES } }]; }
const sd = $getWorkflowStaticData('global'); sd.metaAud = sd.metaAud || {};
const base = 'https://graph.facebook.com/v21.0';
const call = async (method, path, body) => { let a = 0; const max = 5; while (true) { try { return await this.helpers.httpRequest({ method: method, url: base + path, body: body, json: true, returnFullResponse: true }); } catch (e) { if (a >= max - 1) throw e; await new Promise(x => setTimeout(x, Math.min(30000, 500 * 2 ** a))); a++; } } };
const ensure = async (seg, subtype, originId) => {
  const key = 'meta:' + spec.portalId + ':' + seg;
  if (sd.metaAud[key]) return sd.metaAud[key];
  if (dryRun) return 'dry-run-id';
  const body = { name: 'PP ' + seg + ' ' + spec.portalId, subtype: subtype, access_token: token };
  if (subtype === 'CUSTOM') body.customer_file_source = 'USER_PROVIDED_ONLY';
  if (subtype === 'LOOKALIKE') { body.origin_audience_id = originId; body.lookalike_spec = { type: 'similarity', country: $env.META_LOOKALIKE_COUNTRY || 'US' }; }
  const r = await call('POST', '/act_' + act + '/customaudiences', body);
  const id = r.body && r.body.id; sd.metaAud[key] = id; return id;
};
try {
  for (const seg of ['suppression', 'retarget', 'seed']) {
    const d = spec.segments[seg]; if (!d) continue;
    const id = await ensure(seg, 'CUSTOM');
    if (!dryRun && d.adds.length) await call('POST', '/' + id + '/users', { access_token: token, payload: { schema: ['EMAIL'], data: d.adds.map(h => [h]) } });
    if (!dryRun && d.removes.length) await call('DELETE', '/' + id + '/users', { access_token: token, payload: { schema: ['EMAIL'], data: d.removes.map(h => [h]) } });
    RES.segments[seg] = { id: id, added: d.adds.length, removed: d.removes.length };
  }
  if (spec.lookalike && spec.lookalike.ready) {
    const seedId = sd.metaAud['meta:' + spec.portalId + ':seed'];
    RES.lookalike = { id: await ensure('lookalike', 'LOOKALIKE', seedId) };
  }
} catch (e) { RES.status = 'error'; RES.detail = String(e.message || e).slice(0, 200); }
return [{ json: { ...spec, meta: RES } }];

const spec = $('Compute Audiences').first().json;
const dryRun = String($env.PP_DRY_RUN || '').toLowerCase() === 'true';
const RES = { platform: 'google', dryRun: dryRun, segments: {}, status: 'ok', detail: '' };
const cust = $env.GOOGLE_ADS_CUSTOMER_ID, dev = $env.GOOGLE_ADS_DEVELOPER_TOKEN, tok = $env.GOOGLE_ADS_ACCESS_TOKEN;
const lists = { suppression: $env.GOOGLE_USERLIST_SUPPRESSION, retarget: $env.GOOGLE_USERLIST_RETARGET, seed: $env.GOOGLE_USERLIST_SEED };
if (!cust || !dev || !tok) { RES.status = 'error'; RES.detail = 'GOOGLE_ADS_* env unset'; return [{ json: { ...spec, google: RES } }]; }
const base = 'https://googleads.googleapis.com/v17';
const headers = { 'developer-token': dev, 'login-customer-id': cust, Authorization: 'Bearer ' + tok };
const call = async (method, path, body) => { let a = 0; const max = 5; while (true) { try { return await this.helpers.httpRequest({ method: method, url: base + path, headers: headers, body: body, json: true, returnFullResponse: true }); } catch (e) { if (a >= max - 1) throw e; await new Promise(x => setTimeout(x, Math.min(30000, 500 * 2 ** a))); a++; } } };
try {
  for (const seg of ['suppression', 'retarget', 'seed']) {
    const d = spec.segments[seg]; if (!d) continue;
    const list = lists[seg];
    if (!list) { RES.segments[seg] = { skipped: 'no userList env' }; continue; }
    if (dryRun) { RES.segments[seg] = { added: d.adds.length, removed: d.removes.length, dryRun: true }; continue; }
    const created = await call('POST', '/customers/' + cust + '/offlineUserDataJobs:create', { job: { type: 'CUSTOMER_MATCH_USER_LIST', customerMatchUserListMetadata: { userList: list } } });
    const job = created.body && created.body.resourceName;
    const ops = [];
    for (const h of d.adds) ops.push({ create: { userIdentifiers: [{ hashedEmail: h }] } });
    for (const h of d.removes) ops.push({ remove: { userIdentifiers: [{ hashedEmail: h }] } });
    await call('POST', '/' + job + ':addOperations', { operations: ops, enablePartialFailure: true });
    await call('POST', '/' + job + ':run', {});
    RES.segments[seg] = { added: d.adds.length, removed: d.removes.length, job: job };
  }
} catch (e) { RES.status = 'error'; RES.detail = String(e.message || e).slice(0, 200); }
return [{ json: { ...spec, google: RES } }];

const spec = $('Compute Audiences').first().json;
const dryRun = String($env.PP_DRY_RUN || '').toLowerCase() === 'true';
const RES = { platform: 'tiktok', dryRun: dryRun, segments: {}, status: 'ok', detail: '' };
const tok = $env.TIKTOK_ACCESS_TOKEN, adv = $env.TIKTOK_ADVERTISER_ID;
if (!tok || !adv) { RES.status = 'error'; RES.detail = 'TIKTOK_* env unset'; return [{ json: { ...spec, tiktok: RES } }]; }
const sd = $getWorkflowStaticData('global'); sd.ttAud = sd.ttAud || {};
const base = 'https://business-api.tiktok.com/open_api/v1.3';
const headers = { 'Access-Token': tok, 'Content-Type': 'application/json' };
const call = async (path, body) => { let a = 0; const max = 5; while (true) { try { return await this.helpers.httpRequest({ method: 'POST', url: base + path, headers: headers, body: body, json: true, returnFullResponse: true }); } catch (e) { if (a >= max - 1) throw e; await new Promise(x => setTimeout(x, Math.min(30000, 500 * 2 ** a))); a++; } } };
const ensure = async (seg) => { const k = 'tt:' + spec.portalId + ':' + seg; if (sd.ttAud[k]) return sd.ttAud[k]; if (dryRun) return 'dry-run-id'; const r = await call('/dmp/custom_audience/create/', { advertiser_id: adv, custom_audience_name: 'PP ' + seg + ' ' + spec.portalId, audience_sub_type: 'NORMAL' }); const id = r.body && r.body.data && r.body.data.custom_audience_id; sd.ttAud[k] = id; return id; };
try {
  for (const seg of ['suppression', 'retarget', 'seed']) {
    const d = spec.segments[seg]; if (!d) continue;
    const id = await ensure(seg);
    if (!dryRun && d.adds.length) await call('/dmp/custom_audience/update/', { advertiser_id: adv, custom_audience_id: id, action: 'append', calculate_type: 'EMAIL_SHA256', data: d.adds });
    if (!dryRun && d.removes.length) await call('/dmp/custom_audience/update/', { advertiser_id: adv, custom_audience_id: id, action: 'delete', calculate_type: 'EMAIL_SHA256', data: d.removes });
    RES.segments[seg] = { id: id, added: d.adds.length, removed: d.removes.length };
  }
  if (spec.lookalike && spec.lookalike.ready && !dryRun) {
    const seedId = sd.ttAud['tt:' + spec.portalId + ':seed'];
    const r = await call('/dmp/custom_audience/lookalike/create/', { advertiser_id: adv, custom_audience_id: seedId, lookalike_spec: {} });
    RES.lookalike = { id: r.body && r.body.data && r.body.data.custom_audience_id };
  }
} catch (e) { RES.status = 'error'; RES.detail = String(e.message || e).slice(0, 200); }
return [{ json: { ...spec, tiktok: RES } }];

const spec = $('Compute Audiences').first().json;
const all = items.map(i => i.json);
const results = { meta: (all.find(x => x.meta) || {}).meta || null, google: (all.find(x => x.google) || {}).google || null, tiktok: (all.find(x => x.tiktok) || {}).tiktok || null };
const anyError = Object.values(results).some(r => r && r.status === 'error');
const dryRun = Object.values(results).some(r => r && r.dryRun);
const seg = (r) => { if (!r) return 'n/a'; if (r.status === 'error') return 'error: ' + (r.detail || ''); const parts = Object.keys(r.segments || {}).map(k => k + ' +' + (r.segments[k].added || 0) + '/-' + (r.segments[k].removed || 0)); return (r.dryRun ? '(dry-run) ' : '') + (parts.join(', ') || 'no changes'); };
const slackText = ['*Audience Sync* — portal ' + spec.portalId + (dryRun ? ' (DRY-RUN)' : ''), 'Meta: ' + seg(results.meta), 'Google: ' + seg(results.google), 'TikTok: ' + seg(results.tiktok), anyError ? ':warning: a platform errored — snapshot NOT committed, will retry next run' : ':white_check_mark: applied; committing snapshot'].join('\n');
return [{ json: { portalId: spec.portalId, runId: spec.runId, dryRun: dryRun, results: results, anyError: anyError, slackText: slackText } }];

const j = items[0].json;
const url = $env.SLACK_WEBHOOK_URL;
if (!url) { console.log('[audience-sync]\n' + j.slackText); return [{ json: j }]; }
try { await this.helpers.httpRequest({ method: 'POST', url: url, body: { text: j.slackText }, json: true }); } catch (e) {}
return [{ json: j }];
